def update_json(json, path, value):
    '''Update JSON dictionnary PATH with VALUE. Return updated JSON'''
    try:
        first = next(path)
        # check if item is an arra
        if first.startswith('[') and first.endswith(']'):
            try:
                first = int(first[1:-1])
